//! Repository for LoyaltyProgram entities
//!
//! Originally generated by metaphor-schema; now **user-owned** — this exact path is declared under
//! `user_owned` in `metaphor.codegen.yaml`, so the generator skips it wholesale. The custom methods
//! below hold the hand-written LoyaltyProgram SQL (4-layer rule: services orchestrate, repos hold SQL).
//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<LoyaltyProgram, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use rust_decimal::Decimal;
use sqlx::{PgPool, Row};
use uuid::Uuid;

use backbone_orm::company_scope;

use crate::domain::entity::LoyaltyProgram;

/// Table name for LoyaltyProgram entities
pub const TABLE_NAME: &str = "promo.loyalty_programs";

/// Repository for LoyaltyProgram entities.
///
/// All standard CRUD, soft-delete, pagination, and bulk methods are
/// provided automatically via `Deref` to `backbone_orm::GenericCrudRepository`.
pub struct LoyaltyProgramRepository(
    backbone_orm::GenericCrudRepository<LoyaltyProgram, backbone_orm::SoftDelete>,
);

impl std::ops::Deref for LoyaltyProgramRepository {
    type Target = backbone_orm::GenericCrudRepository<LoyaltyProgram, backbone_orm::SoftDelete>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl LoyaltyProgramRepository {
    /// Create a new repository instance.
    pub fn new(pool: PgPool) -> Self {
        Self(backbone_orm::GenericCrudRepository::new(pool, TABLE_NAME))
    }
}

/// Hand-written LoyaltyProgram SQL. Lives here (not in the write service) per the module's 4-layer
/// rule: services orchestrate and own the unit of work, repositories hold the SQL.
///
/// Both reads apply the same active + in-window predicate; they differ only in which factor they
/// project and which connection they ride. `Ok(None)` means "no such usable program" in both — the
/// service is what turns that into `PricingError::ProgramInvalid`.
impl LoyaltyProgramRepository {
    /// An active, in-window program's `(collection_factor, expiry_duration_days)` — what accrual needs.
    ///
    /// RLS scope (ADR-0008): company on the parameter — the caller wraps this in
    /// `with_company_scope(Some(company_id))`. The explicit `company_id = $2` stays as
    /// defense-in-depth.
    pub async fn find_active_collection(
        &self,
        pool: &PgPool,
        company_id: Uuid,
        program_id: Uuid,
        at: chrono::DateTime<chrono::Utc>,
    ) -> Result<Option<(Decimal, Option<i32>)>, sqlx::Error> {
        let row = company_scope::fetch_optional_row_scoped(
            pool,
            sqlx::query(
                r#"SELECT collection_factor, expiry_duration_days FROM promo.loyalty_programs
                   WHERE id = $1 AND company_id = $2 AND is_active = true
                     AND (metadata->>'deleted_at') IS NULL
                     AND from_date <= $3 AND (to_date IS NULL OR to_date >= $3)"#,
            )
            .bind(program_id)
            .bind(company_id)
            .bind(at),
        )
        .await?;
        Ok(row.map(|r| (r.get("collection_factor"), r.get("expiry_duration_days"))))
    }

    /// An active, in-window program's `conversion_factor` (currency per point).
    ///
    /// Takes the CALLER'S connection: it is read INSIDE the redemption tx, so the factor that prices a
    /// burn is the one the serialized balance check saw. The caller has already bound the company on it
    /// (`bind_company_on`) — don't re-bind here.
    pub async fn find_active_conversion(
        &self,
        conn: &mut sqlx::PgConnection,
        company_id: Uuid,
        program_id: Uuid,
        at: chrono::DateTime<chrono::Utc>,
    ) -> Result<Option<Decimal>, sqlx::Error> {
        sqlx::query_scalar(
            r#"SELECT conversion_factor FROM promo.loyalty_programs
               WHERE id = $1 AND company_id = $2 AND is_active = true
                 AND (metadata->>'deleted_at') IS NULL
                 AND from_date <= $3 AND (to_date IS NULL OR to_date >= $3)"#,
        )
        .bind(program_id)
        .bind(company_id)
        .bind(at)
        .fetch_optional(conn)
        .await
    }
}

backbone_core::impl_crud_repository!(LoyaltyProgramRepository, LoyaltyProgram, soft_delete);
